+                }
+            }
+        }
+        return nil
+    }
+
+    private static func value(for path: [String], in contexts: [[String: Any]]) -> Any? {
+        for context in contexts {
+            var cursor: Any? = context
+            for key in path {
+                if let dict = cursor as? [String: Any] {
+                    cursor = dict[key]
+                } else {
+                    cursor = nil
+                }
+            }
+            if cursor != nil {
+                return cursor
+            }
+        }
+        return nil
+    }
