+        return OpenCodeUsageSnapshot(
+            rollingUsagePercent: rollingPercent,
+            weeklyUsagePercent: weeklyPercent,
+            rollingResetInSec: rollingReset,
+            weeklyResetInSec: weeklyReset,
+            updatedAt: now)
+    }
