+        else {
+            return nil
+        }
+
+        if let snapshot = self.parseUsageJSON(object: object, now: now) {
+            return snapshot
+        }
+
+        if let snapshot = self.parseUsageFromCandidates(object: object, now: now) {
+            return snapshot
